fn legacy_kg_explain( graph: &mut eden_garm::HyperGraph, ids: RuntimeNodeIds, topic: &str, ) -> String { let pack = Self::context_pack(graph, ids, topic, 3, 5); if pack.path_explanations.is_empty() { String::new() } else { Self::apply_cag_feedback(graph, ids, &pack, true); format!( "[KG-REASON] {}
{}
{}
{}
", topic, pack.path_explanations.join("
"), Self::cag_stance_line(&pack), Self::cag_trace_line(&pack) ) } }

fn reason_report( graph: &mut eden_garm::HyperGraph, ids: RuntimeNodeIds, intent: &str, topic: &str, ) -> String { let pack = Self::context_pack(graph, ids, topic, 2, 5); let Some(node) = graph.nodes.get_mut(ids.legacy_reason) else { return "legacy_reason node not found
".to_string(); }; let Some(reason) = node .as_any_mut() .downcast_mut::<eden_garm::nodes::legacy_reason::LegacyReasonNode>() else { return "legacy_reason node type mismatch
".to_string(); }; let out = format!( "{}
{}
{}
", reason.answer_intent(intent, topic, &pack.memory_facts), Self::cag_stance_line(&pack), Self::cag_trace_line(&pack) ); Self::apply_cag_feedback(graph, ids, &pack, pack.context_quality >= 0.35); out }
